ee:message.ee:set-payload:
%dw 2.0 output application/json skipNullOn="everywhere"
--- {
"status": if ((payload.errorType.identifier == "UNKNOWN") or (error.errorType.identifier == "COMPOSITE_ROUTING")) "BAD_REQUEST" else payload.errorType.identifier[0],
"code": vars.httpStatus, "shortMessage": if ((payload.errorType.identifier == "UNKNOWN") or (error.errorType.identifier == "COMPOSITE_ROUTING")) "BAD_REQUEST" else payload.errorType.identifier[0],
}
